local ScannerBox      = Tabs.Scanner:AddLeftGroupbox("Bestes Pet pro Basis ")
local ScanStatusLabel = ScannerBox:AddLabel("Status: Drücke „Scan“, um zu beginnen", true)
ScannerBox:AddDivider()

local ResultLabels = {}
for i = 1, 10 do
    table.insert(ResultLabels, ScannerBox:AddLabel("", true))
end

local bestPlotRef = nil

ScannerBox:AddButton({
    Text    = "Scan ",
    Tooltip = "Alle Basen scannen und das beste Pet auf jeder Basis finden",
    Func    = function()
        ScanStatusLabel:SetText("Status: Scanne...")
        bestPlotRef = nil
        for _, lbl in ipairs(ResultLabels) do lbl:SetText("") end
        local plotResults = {}
        for _, plot in pairs(workspace.Plots:GetChildren()) do
            local owner = plot:GetAttribute("Owner") or "Unknown"
            if owner == player.Name then continue end
            local slots = plot:FindFirstChild("Slots")
            if slots then
                local bestPet, bestCashRaw = nil, nil
                for _, slot in pairs(slots:GetChildren()) do
                    local placed = slot:FindFirstChild("PlacedPart")
                    if placed then
                        local id       = placed:GetAttribute("ID")
                        local level    = placed:GetAttribute("Level") or 1
                        local mutation = placed:GetAttribute("Mutation") or "None"
                        if id then
                            local cashRaw = M.getCashRaw(id, level, mutation)
                            if cashRaw then
                                local isHigher = bestCashRaw == nil
                                if not isHigher then
                                    local ok, cmp = pcall(function() return cashRaw > bestCashRaw end)
                                    isHigher = ok and cmp
                                end
                                if isHigher then
                                    bestCashRaw = cashRaw
                                    bestPet = {
                                        id       = id,
                                        level    = level,
                                        mutation = mutation,
                                        rarity   = M.getRarity(id),
                                        cash     = tostring(cashRaw) .. "/s"
                                    }
                                end
                            end
                        end
                    end
                end
                if bestPet then
                    table.insert(plotResults, {
                        plot    = plot.Name,
                        plotObj = plot,
                        owner   = owner,
                        pet     = bestPet,
                        cashRaw = bestCashRaw
                    })
                end
            end
        end
        table.sort(plotResults, function(a, b)
            local ok, result = pcall(function() return a.cashRaw > b.cashRaw end)
            return ok and result
        end)
        local count = math.min(#plotResults, 10)
        for i = 1, count do
            local e = plotResults[i]
            ResultLabels[i]:SetText(string.format(
                "#%d [Base: %s] Owner: %s | Pet: %s | Level: %d | Mutation: %s | Rarity: %s | Cash: %s",
                i, e.plot, e.owner,
                e.pet.id, e.pet.level, e.pet.mutation, e.pet.rarity, e.pet.cash
            ))
        end
        if count == 0 then
            ScanStatusLabel:SetText("Status: Keine Ergebnisse gefunden.")
        else
            ScanStatusLabel:SetText("Status: Complete — " .. count .. " Base(s) Scanned.")
            bestPlotRef = plotResults[1].plotObj
        end
    end,
})

ScannerBox:AddButton({
    Text    = "Zum besten Pet teleportieren ",
    Tooltip = "Zur am höchsten eingestuften Basis teleportieren",
    Func    = function()
        if not bestPlotRef then
            Library:Notify({ Title = "Scanner", Description = "Keine Scan-Ergebnisse. Drücke zuerst „Scan“.", Time = 3 })
            return
        end
        M.ForcedTP(bestPlotRef:GetPivot() * CFrame.new(0, 5, 0))
    end,
})

