WebhookGroup:AddButton({
    Text = "Webhook testen ",
    Func = function()
        if not DiscordState.WebhookURL or DiscordState.WebhookURL == "" then
            Library:Notify({ Title = "Discord", Description = "Es wurde keine Webhook-URL festgelegt.", Time = 3 })
            return
        end
        local HttpService = game:GetService("HttpService")
        local payload = HttpService:JSONEncode({
            content  = "@everyone\n✅ **COMBOWICK** Webhook-Test erfolgreich!\n👤 **Spieler:** " .. player.Name,
            username = "COMBOWICK Alert",
        })
        local ok, err = pcall(function()
            request({
                Url     = DiscordState.WebhookURL,
                Method  = "POST",
                Headers = { ["Content-Type"] = "application/json" },
                Body    = payload,
            })
        end)
        if ok then
            Library:Notify({ Title = "Discord", Description = "Testbenachrichtigung erfolgreich gesendet.", Time = 3 })
        else
            Library:Notify({ Title = "Discord", Description = "Fehler: " .. tostring(err), Time = 5 })
        end
    end,
})

